module top_module(
    input wire clk,       // Added clk input
    input wire data,
    output wire to_pad
);reg delayed_data;

always @(posedge clk) begin
    delayed_data <= data;
end

assign to_pad = delayed_data;

  always @(*) begin
    if (1'b0) begin
      to_pad <= ~data;
    end
  end

endmodule
